	private static void assertCandidateTelemetryMatches(PlanSelectionSnapshot snapshot, int candidateIndex, double cost,
			double uncertainty) {
		if (candidateIndex < 0 || candidateIndex >= snapshot.getCandidates().size()) {
			return;
		}
		assertEquals(snapshot.getCandidates().get(candidateIndex).getEstimatedTotalCost(), cost, 0.0000001d);
		assertEquals(snapshot.getCandidates().get(candidateIndex).getTotalUncertainty(), uncertainty, 0.0000001d);
	}

	private static void assertCandidateSignatureMatches(PlanSelectionSnapshot snapshot, int candidateIndex,
			String signature) {
		if (candidateIndex < 0 || candidateIndex >= snapshot.getCandidates().size()) {
			return;
		}
		assertEquals(snapshot.getCandidates().get(candidateIndex).getPlanSignature(), signature);
	}

	private static void assertTraceContainsBooleanValue(String traceContents, String field, Boolean value) {
		assertTrue(traceContents.contains("\"" + field + "\":" + value));
	}

	private static void assertTraceContainsNumericValue(String traceContents, String field, Number value) {
		assertTrue(traceContents.contains("\"" + field + "\":" + value));
	}

	private static void assertTraceContainsStringValue(String traceContents, String field, String value) {
		assertTrue(traceContents.contains("\"" + field + "\":\"" + value + "\""));
	}

	private static int configuredPlanTraceTopK() {
		try {
			Field field = LearnedQueryJoinOptimizer.class.getDeclaredField("PLAN_TRACE_TOPK");
			field.setAccessible(true);
			return ((Number) field.get(null)).intValue();
		} catch (ReflectiveOperationException exception) {
			fail("Expected optimizer static telemetry field PLAN_TRACE_TOPK", exception);
			return -1;
		}
	}

	private static String invokeStabilityGetter(PlanSelectionSnapshot snapshot, String methodName) {
		try {
			Method method = snapshot.getClass().getMethod(methodName);
			return (String) method.invoke(snapshot);
		} catch (ReflectiveOperationException exception) {
			fail("Expected plan stability telemetry getter: " + methodName, exception);
			return null;
		}
	}

