	@SuppressWarnings("unchecked")
	private static void clearWinnerCache() throws Exception {
		Field field = LearnedQueryJoinOptimizer.class.getDeclaredField("EXPLORE_WINNER_CACHE");
		field.setAccessible(true);
		Map<String, ?> cache = (Map<String, ?>) field.get(null);
		cache.clear();
	}

	@SuppressWarnings("unchecked")
	private static Object findPlanOutcomeStatsEntry(String templateHash, String planSignature) throws Exception {
		Field field = LearnedQueryJoinOptimizer.class.getDeclaredField("PLAN_OUTCOME_STATS");
		field.setAccessible(true);
		Map<?, ?> stats = (Map<?, ?>) field.get(null);
		for (Entry<?, ?> entry : stats.entrySet()) {
			Object key = entry.getKey();
			if (templateHash.equals(readStringField(key, "templateHash"))
					&& planSignature.equals(readStringField(key, "planSignature"))) {
				return entry.getValue();
			}
		}
		return null;
	}

	private static String readStringField(Object target, String fieldName) throws Exception {
		Field field = target.getClass().getDeclaredField(fieldName);
		field.setAccessible(true);
		return (String) field.get(target);
	}

	private static long readLongField(Object target, String fieldName) throws Exception {
		Field field = target.getClass().getDeclaredField(fieldName);
		field.setAccessible(true);
		return ((Number) field.get(target)).longValue();
	}

	private static double readDoubleField(Object target, String fieldName) throws Exception {
		Field field = target.getClass().getDeclaredField(fieldName);
		field.setAccessible(true);
		return ((Number) field.get(target)).doubleValue();
	}

